import{_ as e,o as t,c as o,a}from"./app.1f0d3914.js";const _=JSON.parse('{"title":"Yoahtl v. TheOrangeWizard (and 14uu), Nov 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Suit","slug":"suit","link":"#suit","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/yoahtl_v_theorangewizard_(and_14uu)_nov_2017.md","lastUpdated":1666025933000}'),i={name:"government/court-cases-precedents/yoahtl_v_theorangewizard_(and_14uu)_nov_2017.md"},n=a('<h1 id="yoahtl-v-theorangewizard-and-14uu-nov-2017" tabindex="-1">Yoahtl v. TheOrangeWizard (and 14uu), Nov 2017 <a class="header-anchor" href="#yoahtl-v-theorangewizard-and-14uu-nov-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Bench Trial</p><p><strong>Date</strong>: 15th November 2017</p><h2 id="suit" tabindex="-1">Suit <a class="header-anchor" href="#suit" aria-hidden="true">#</a></h2><p>Bgbba alleges that the government has the right to derelict spawners to ensure public access to materials if the individual owner is not maintaining their improvements to provide access or goods for sale.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><blockquote><p>Simply put: dereliction is based on usage. Allow me to link the relevant council decision: The Alcuahtl assigns dereliction duty to an individual councillor. This duty cannot be delegated. The longest-inactive players are the first available for eviction and dereliction. The Derelictor and Alcuahtl have discretion over the need to derelict, but but cannot abuse the power. The other two councillors may force the Alcuahtl to reconsider their choice of derelictor, but may not force a resignation without proof of wrongdoing.</p></blockquote><blockquote><p>The way dereliction has always run, businesses are only considered &#39;used&#39; if they continue to produce products for regular sale. I argue that grinders are:</p><ol><li>Businesses</li><li>Dereliction rules apply to them</li><li>14uu hasn&#39;t produced products for sale from his grinder in weeks</li></ol></blockquote><p>-bgbba</p><p>.</p><blockquote><p>I believe that while derelicting functional grinders is unfair, the government is fully within its rights under the dereliction act to do so. Because discretion is the determining factor and abuse is undefined, I cannot see that 14uu and I have any legal defense against bgbba if he wishes to derelict our property and claim it for the state.</p></blockquote><p>-TheOrangeWizard</p><p>People question what the definition of &#39;abuse&#39; is.</p><p>bgbba says the council is the only body which can define &#39;abuse&#39;</p><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>Dereliction law redefined, bgbba&#39;s dereliction overturned.</p>',16),r=[n];function s(d,l,c,h,u,p){return t(),o("div",null,r)}const b=e(i,[["render",s]]);export{_ as __pageData,b as default};
